// Nilai representatif dari sebuah indikator
// pada level NASIONAL. Dipakai untuk membangun grafik lintas-provinsi
// (sumbu kategori = provinsi). Mengambil titik terbaru dari series yang
// paling rapat: bulanan -> triwulanan -> tahunan.
export const getNationalLatestValue = (source, kode) => {
  const entry = getDummyEntry(source, kode);
  if (!entry) return null;

  const pickLast = (arr) => {
    if (!Array.isArray(arr)) return null;
    for (let i = arr.length - 1; i >= 0; i -= 1) {
      const v = arr[i];
      if (typeof v === "number" && Number.isFinite(v)) return v;
    }
    return null;
  };

  return (
    pickLast(entry.series?.monthly?.data) ??
    pickLast(entry.series?.quarterly?.data) ??
    pickLast(entry.series?.yearly?.data) ??
    null
  );
};

// Nilai sebuah indikator untuk provinsi tertentu,
// = nilai nasional x faktor provinsi. "indonesia" -> nilai nasional.
export const getProvinceIndicatorValue = (province, source, kode) => {
  const base = getNationalLatestValue(source, kode);
  if (base === null) return null;
  const factor = getProvinceScale(province, kode);
  return Number((base * factor).toFixed(2));
};

const GLOBAL_SOURCES = ["pkrt", "pkp", "pmtb", "eksim"];

const emptySeries = () => ({ data: [], periods: [] });

// =========================================================
// MODE WILAYAH (PROVINSI)
// Setiap provinsi memiliki nilai indikator sendiri yang berbeda
// namun struktur datanya tetap identik dengan data nasional.
// Faktor dihitung deterministik per (provinsi + kode indikator)
// sehingga: konsisten antar reload, berbeda antar provinsi,
// dan berbeda antar indikator. "indonesia" = data nasional (faktor 1).
// =========================================================
const NATIONAL_PROVINCE = "indonesia";

const hashString = (text = "") => {
  let hash = 2166136261;
  const str = String(text);
  for (let i = 0; i < str.length; i += 1) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0) / 4294967295; // 0..1
};

export const getProvinceScale = (province, kode = "") => {
  const key = String(province ?? "").toLowerCase().trim();
  if (!key || key === NATIONAL_PROVINCE) return 1;

  const base = hashString(`${key}::scale`);
  const perIndicator = hashString(`${key}::${kode}`);
  const factor = 0.45 + base * 0.9 + (perIndicator - 0.5) * 0.18;

  return Math.max(0.2, Number(factor.toFixed(4)));
};

const scaleSeriesData = (series, factor) => {
  if (!series || factor === 1) return series ?? emptySeries();
  const data = Array.isArray(series.data)
    ? series.data.map((value) =>
        typeof value === "number" && Number.isFinite(value)
          ? Number((value * factor).toFixed(2))
          : value
      )
    : [];
  return { ...series, data };
};

// Membuat salinan entry DUMMY_DATA dengan series nilai (level) yang
// sudah diskalakan sesuai provinsi. Series pertumbuhan (%) dibiarkan
// karena rasio pertumbuhan tidak terpengaruh penskalaan proporsional.
const getScaledEntry = (entry, province, kode) => {
  const factor = getProvinceScale(province, kode);
  if (!entry || factor === 1) return entry;

  return {
    ...entry,
    series: {
      monthly: scaleSeriesData(entry.series?.monthly, factor),
      quarterly: scaleSeriesData(entry.series?.quarterly, factor),
      yearly: scaleSeriesData(entry.series?.yearly, factor),
    },
    growth: entry.growth,
  };
};

// =========================================================
// HELPER: Ambil dataset dari DUMMY_DATA
// =========================================================
const getDummyEntry = (source, kode) => {
  const key = `${String(source).toLowerCase()}::${String(kode)}`;
  return DUMMY_DATA[key] ?? null;
};

const getDummyIndikator = (source) => {
  return Object.values(DUMMY_DATA)
    .filter((entry) => entry.indikator && entry.indikator.kode.startsWith(
      source === "pkrt" ? "MPKRT" :
      source === "pkp"  ? "MPKP"  :
      source === "pmtb" ? "MPMTB" :
      source === "eksim"? "MEKSIM":
      source === "pdb"  ? "Q"     : "X"
    ))
    .map((entry) => entry.indikator);
};

const generateAcronym = (text = "") => {
  return String(text)
    .replace(/[^a-zA-Z0-9\s]/g, " ")
    .split(/\s+/)
    .filter(Boolean)
    .map((word) => {
      const cleanWord = String(word).trim();
      if (
        cleanWord.length > 1 &&
        cleanWord.length <= 5 &&
        cleanWord === cleanWord.toUpperCase() &&
        /[A-Z]/.test(cleanWord)
      ) {
        return cleanWord;
      }
      return cleanWord.charAt(0).toUpperCase();
    })
    .join("");
};

const toShortCode = (source, kode, deskripsi) => {
  const prefix =
    String(kode ?? "").charAt(0).toUpperCase() ||
    String(source ?? "").toUpperCase();
  const acronym = generateAcronym(deskripsi);
  return `${prefix}-${acronym || String(kode ?? "").toUpperCase()}`;
};

const buildAggregationAvailability = ({ freq = "", konversi = "" } = {}) => {
  const normalizedFreq = String(freq ?? "").trim().toUpperCase();
  const normalizedKonversi = String(konversi ?? "").trim().toUpperCase();
  const isNaNConversion = normalizedKonversi === "NAN";

  if (normalizedFreq === "M") {
    return {
      allowMonthly: true,
      allowQuarterly: !isNaNConversion,
      allowYearly: !isNaNConversion,
    };
  }
  if (normalizedFreq === "Q") {
    return {
      allowMonthly: false,
      allowQuarterly: true,
      allowYearly: !isNaNConversion,
    };
  }
  if (normalizedFreq === "Y" || normalizedFreq === "A") {
    return {
      allowMonthly: false,
      allowQuarterly: false,
      allowYearly: true,
    };
  }
  return { allowMonthly: true, allowQuarterly: true, allowYearly: true };
};

// =========================================================
// EXPORTED FUNCTIONS
// =========================================================

export const fetchIndicatorsBySource = async (source) => {
  const sourceKey = String(source ?? "").toLowerCase();
  const items = Object.values(DUMMY_DATA)
    .filter((entry) => {
      const kode = entry?.indikator?.kode ?? "";
      if (sourceKey === "pkrt")  return kode.startsWith("MPKRT");
      if (sourceKey === "pkp")   return kode.startsWith("MPKP");
      if (sourceKey === "pmtb")  return kode.startsWith("MPMTB");
      if (sourceKey === "eksim") return kode.startsWith("MEKSIM");
      if (sourceKey === "pdb")   return kode.startsWith("Q");
      return false;
    })
    .map((entry, index) => ({
      source: sourceKey,
      kode: String(entry.indikator.kode),
      deskripsi: String(entry.indikator.deskripsi),
      apiFreqPrefix: String(entry.indikator.kode).charAt(0).toUpperCase(),
      satuan: String(entry.indikator.satuan ?? ""),
    }));
  return items;
};

export const buildDynamicDatasetFromApi = async ({ source, kode, deskripsi, satuan = "", province = NATIONAL_PROVINCE }) => {
  const sourceKey = String(source ?? "").toLowerCase();
  const baseEntry = getDummyEntry(sourceKey, kode);
  if (!baseEntry) return null;

  const entry = getScaledEntry(baseEntry, province, kode);

  const ind = entry.indikator;
  const resolvedUnit = String(ind?.satuan ?? satuan ?? "").trim();
  const resolvedFreq = String(ind?.freq ?? "").trim().toUpperCase();
  const resolvedKonversi = String(ind?.konversi ?? "").trim();
  const aggregationAvailability = buildAggregationAvailability({
    freq: resolvedFreq,
    konversi: resolvedKonversi,
  });

  const monthly = entry.series.monthly ?? emptySeries();
  const quarterly = entry.series.quarterly ?? emptySeries();
  const yearly = entry.series.yearly ?? emptySeries();

  return {
    id: `${sourceKey}-${String(kode)}`,
    label: String(kode),
    indicatorName: String(deskripsi),
    groupCode: toShortCode(sourceKey, kode, deskripsi),
    source: sourceKey,
    apiCode: String(kode),
    apiFreqPrefix: String(kode).charAt(0).toUpperCase(),
    valueUnitLabel: resolvedUnit,
    growthUnitLabel: "%",
    kodeMeta: { freq: resolvedFreq, konversi: resolvedKonversi },
    aggregationAvailability,
    meta: {
      kode: String(kode),
      deskripsi: String(deskripsi),
      satuan: resolvedUnit,
      freq: resolvedFreq,
      konversi: resolvedKonversi,
      source: sourceKey,
    },
    rawFrequency:
      (monthly.periods?.length ?? 0) > 0
        ? "monthly"
        : (quarterly.periods?.length ?? 0) > 0
        ? "quarterly"
        : (yearly.periods?.length ?? 0) > 0
        ? "yearly"
        : "unknown",
    derivedPeriods: {
      monthly: monthly.periods ?? [],
      quarterly: quarterly.periods ?? [],
      yearly: yearly.periods ?? [],
    },
    series: {
      monthly: monthly.data ?? [],
      quarterly: quarterly.data ?? [],
      yearly: yearly.data ?? [],
    },
    growth: {
      monthly: {
        mtom: entry.growth.mtom ?? emptySeries(),
        yony_m: entry.growth.yony_m ?? emptySeries(),
        ytod: entry.growth.ytod ?? emptySeries(),
      },
      quarterly: {
        qtoq: entry.growth.qtoq ?? emptySeries(),
        yony: entry.growth.yony ?? emptySeries(),
        ctoc: entry.growth.ctoc ?? emptySeries(),
      },
      yearly: entry.growth.annual ?? emptySeries(),
    },
    tension: 0.4,
  };
};

export const buildStaticDatasetFromApi = async ({ source, kode, deskripsi, satuan = "", province = NATIONAL_PROVINCE }) => {
  return buildDynamicDatasetFromApi({ source, kode, deskripsi, satuan, province });
};

export const buildPdbStaticDatasetFromComponent = async ({ kode, deskripsi, measure = "nilai", province = NATIONAL_PROVINCE }) => {
  const baseEntry = getDummyEntry("pdb", kode);
  if (!baseEntry) return null;

  const entry = getScaledEntry(baseEntry, province, kode);

  const ind = entry.indikator;
  const resolvedUnit = String(ind?.satuan ?? "").trim();

  const quarterly = entry.series.quarterly ?? emptySeries();
  const yearly = entry.series.yearly ?? emptySeries();

  return {
    id: `pdb-static-${String(kode)}-${measure === "nilai" ? "ADHB" : "ADHK"}`,
    label: String(kode),
    indicatorName: String(deskripsi),
    deskripsi: String(deskripsi),
    kode: String(kode),
    sourceCode: String(kode),
    satuan: resolvedUnit,
    unit: resolvedUnit,
    groupCode: String(kode),
    source: "pdb",
    apiCode: String(kode),
    apiFreqPrefix: String(kode).charAt(0).toUpperCase(),
    valueUnitLabel: resolvedUnit,
    growthUnitLabel: "%",
    meta: {
      kode: String(kode),
      deskripsi: String(deskripsi),
      satuan: resolvedUnit,
      unit: resolvedUnit,
      source: "pdb",
    },
    rawFrequency:
      (quarterly.periods?.length ?? 0) > 0
        ? "quarterly"
        : (yearly.periods?.length ?? 0) > 0
        ? "yearly"
        : "quarterly",
    derivedPeriods: {
      monthly: [],
      quarterly: quarterly.periods ?? [],
      yearly: yearly.periods ?? [],
    },
    series: {
      monthly: [],
      quarterly: quarterly.data ?? [],
      yearly: yearly.data ?? [],
    },
    growth: {
      monthly: {
        mtom: emptySeries(),
        yony_m: emptySeries(),
        ytod: emptySeries(),
      },
      quarterly: {
        qtoq: entry.growth.qtoq ?? emptySeries(),
        yony: entry.growth.yony ?? emptySeries(),
        ctoc: entry.growth.ctoc ?? emptySeries(),
      },
      yearly: entry.growth.annual ?? emptySeries(),
    },
    tension: 0.4,
  };
};

export const getGlobalSourceOptions = () =>
  GLOBAL_SOURCES.map((value) => ({
    value,
    label: value.toUpperCase(),
  }));

// Backward compat
export const fetchPkrtIndicators = async () => fetchIndicatorsBySource("pkrt");

export const buildDatasetFromApi = async ({ kode, deskripsi, satuan = "" }) =>
  buildDynamicDatasetFromApi({ source: "pkrt", kode, deskripsi, satuan });

